package com.dlx.sshterm

import android.content.Intent
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.runtime.LaunchedEffect
import androidx.compose.runtime.mutableStateOf
import androidx.compose.ui.Modifier
import com.dlx.sshterm.navigation.AppRoutes
import androidx.navigation.compose.rememberNavController
import com.dlx.sshterm.navigation.AppNavHost
import com.dlx.sshterm.ui.theme.PrivateSSHTheme
import dagger.hilt.android.AndroidEntryPoint

/**
 * Main activity for the Private SSH application.
 */
@AndroidEntryPoint
class MainActivity : AppCompatActivity() {

    private val pendingTerminalRoute = mutableStateOf<String?>(null)

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        pendingTerminalRoute.value = resolveTerminalRoute(intent)

        enableEdgeToEdge()

        setContent {
            val navController = rememberNavController()
            PrivateSSHTheme {
                LaunchedEffect(pendingTerminalRoute.value) {
                    pendingTerminalRoute.value?.let { route ->
                        navController.navigate(route) {
                            launchSingleTop = true
                        }
                        pendingTerminalRoute.value = null
                    }
                }
                AppNavHost(
                    navController = navController,
                    modifier = Modifier.fillMaxSize()
                )
            }
        }
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        pendingTerminalRoute.value = resolveTerminalRoute(intent)
    }

    private fun resolveTerminalRoute(intent: Intent?): String? {
        val sessionId = intent?.getStringExtra("session_id")?.takeIf { it.isNotBlank() } ?: return null
        return AppRoutes.terminal(sessionId)
    }
}

package com.dlx.sshterm.navigation

import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.navigation.NavHostController
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.navArgument
import com.dlx.sshterm.ui.hostedit.HostEditScreen
import com.dlx.sshterm.ui.hostlist.HostListScreen
import com.dlx.sshterm.ui.diagnostics.DiagnosticsScreen
import com.dlx.sshterm.ui.settings.SettingsScreen
import com.dlx.sshterm.ui.terminal.TerminalScreen

/**
 * Main navigation host for the application.
 */
@Composable
fun AppNavHost(
    navController: NavHostController,
    modifier: Modifier = Modifier,
    startDestination: String = AppRoutes.HOST_LIST
) {
    NavHost(
        modifier = modifier,
        navController = navController,
        startDestination = startDestination
    ) {
        // Host List Screen
        composable(AppRoutes.HOST_LIST) {
            HostListScreen(
                onNavigateToAddHost = {
                    navController.navigate(AppRoutes.HOST_CREATE)
                },
                onNavigateToEditHost = { hostId ->
                    navController.navigate(AppRoutes.hostEdit(hostId))
                },
                onNavigateToTerminal = { hostId ->
                    navController.navigate(AppRoutes.terminal(hostId))
                },
                onNavigateToSettings = {
                    navController.navigate(AppRoutes.SETTINGS)
                }
            )
        }

        // Create Host Screen
        composable(AppRoutes.HOST_CREATE) {
            HostEditScreen(
                onBack = { navController.popBackStack() }
            )
        }

        // Edit Host Screen
        composable(
            route = AppRoutes.HOST_EDIT_ROUTE,
            arguments = listOf(
                navArgument(AppRoutes.HOST_ID_ARG) {
                    type = NavType.StringType
                }
            )
        ) {
            HostEditScreen(
                onBack = { navController.popBackStack() }
            )
        }

        composable(
            route = AppRoutes.TERMINAL_ROUTE,
            arguments = listOf(
                navArgument(AppRoutes.HOST_ID_ARG) {
                    type = NavType.StringType
                }
            )
        ) { backStackEntry ->
            val hostId = backStackEntry.arguments?.getString(AppRoutes.HOST_ID_ARG) ?: return@composable
            TerminalScreen(
                hostId = hostId,
                onNavigateBack = { navController.popBackStack() },
                onNavigateToDiagnostics = {
                    navController.navigate(AppRoutes.DIAGNOSTICS)
                }
            )
        }

        composable(AppRoutes.SETTINGS) {
            SettingsScreen(
                onNavigateBack = { navController.popBackStack() },
                onNavigateToDiagnostics = {
                    navController.navigate(AppRoutes.DIAGNOSTICS)
                }
            )
        }

        composable(AppRoutes.DIAGNOSTICS) {
            DiagnosticsScreen(
                onNavigateBack = { navController.popBackStack() }
            )
        }
    }
}
